307     // other, turn this into an *inclusive* or.
308     //    e.g. (A & C1)^(B & C2) -> (A & C1)|(B & C2) iff C1&C2 == 0
309     if (DemandedMask.isSubsetOf(RHSKnown.Zero | LHSKnown.Zero)) {
310       Instruction *Or =
311           BinaryOperator::CreateOr(I->getOperand(0), I->getOperand(1));
312       if (DemandedMask.isAllOnes())
313         cast<PossiblyDisjointInst>(Or)->setIsDisjoint(true);
314       Or->takeName(I);
315       return InsertNewInstWith(Or, I->getIterator());
316     }
317 
318     // If all of the demanded bits on one side are known, and all of the set
319     // bits on that side are also known to be set on the other side, turn this
320     // into an AND, as we know the bits will be cleared.
321     //    e.g. (X | C1) ^ C2 --> (X | C1) & ~C2 iff (C1&C2) == C2
322     if (DemandedMask.isSubsetOf(RHSKnown.Zero|RHSKnown.One) &&
323         RHSKnown.One.isSubsetOf(LHSKnown.One)) {
324       Constant *AndC = Constant::getIntegerValue(VTy,
325                                                  ~RHSKnown.One & DemandedMask);
326       Instruction *And = BinaryOperator::CreateAnd(I->getOperand(0), AndC);
327       return InsertNewInstWith(And, I->getIterator());
328     }
329 
330     // If the RHS is a constant, see if we can change it. Don't alter a -1
331     // constant because that's a canonical 'not' op, and that is better for
332     // combining, SCEV, and codegen.
333     const APInt *C;
334     if (match(I->getOperand(1), m_APInt(C)) && !C->isAllOnes()) {
335       if ((*C | ~DemandedMask).isAllOnes()) {
336         // Force bits to 1 to create a 'not' op.
337         I->setOperand(1, ConstantInt::getAllOnesValue(VTy));
338         return I;
339       }
340       // If we can't turn this into a 'not', try to shrink the constant.
341       if (ShrinkDemandedConstant(I, 1, DemandedMask))
342         return I;
343     }
344 
345     // If our LHS is an 'and' and if it has one use, and if any of the bits we
346     // are flipping are known to be set, then the xor is just resetting those
347     // bits to zero.  We can just knock out bits from the 'and' and the 'xor',
348     // simplifying both of them.
349     if (Instruction *LHSInst = dyn_cast<Instruction>(I->getOperand(0))) {
350       ConstantInt *AndRHS, *XorRHS;
351       if (LHSInst->getOpcode() == Instruction::And && LHSInst->hasOneUse() &&
352           match(I->getOperand(1), m_ConstantInt(XorRHS)) &&
353           match(LHSInst->getOperand(1), m_ConstantInt(AndRHS)) &&
354           (LHSKnown.One & RHSKnown.One & DemandedMask) != 0) {
355         APInt NewMask = ~(LHSKnown.One & RHSKnown.One & DemandedMask);
356 
357         Constant *AndC = ConstantInt::get(VTy, NewMask & AndRHS->getValue());
358         Instruction *NewAnd = BinaryOperator::CreateAnd(I->getOperand(0), AndC);
359         InsertNewInstWith(NewAnd, I->getIterator());
360 
361         Constant *XorC = ConstantInt::get(VTy, NewMask & XorRHS->getValue());
362         Instruction *NewXor = BinaryOperator::CreateXor(NewAnd, XorC);
363         return InsertNewInstWith(NewXor, I->getIterator());
364       }
365     }
366     break;
367   }
368   case Instruction::Select: {
369     if (SimplifyDemandedBits(I, 2, DemandedMask, RHSKnown, Depth + 1, Q) ||
370         SimplifyDemandedBits(I, 1, DemandedMask, LHSKnown, Depth + 1, Q))
371       return I;
372 
373     // If the operands are constants, see if we can simplify them.
374     // This is similar to ShrinkDemandedConstant, but for a select we want to
375     // try to keep the selected constants the same as icmp value constants, if
376     // we can. This helps not break apart (or helps put back together)
377     // canonical patterns like min and max.
378     auto CanonicalizeSelectConstant = [](Instruction *I, unsigned OpNo,
379                                          const APInt &DemandedMask) {
380       const APInt *SelC;
381       if (!match(I->getOperand(OpNo), m_APInt(SelC)))
382         return false;
383 
384       // Get the constant out of the ICmp, if there is one.
385       // Only try this when exactly 1 operand is a constant (if both operands
386       // are constant, the icmp should eventually simplify). Otherwise, we may
387       // invert the transform that reduces set bits and infinite-loop.
388       Value *X;
389       const APInt *CmpC;
390       ICmpInst::Predicate Pred;
391       if (!match(I->getOperand(0), m_ICmp(Pred, m_Value(X), m_APInt(CmpC))) ||
392           isa<Constant>(X) || CmpC->getBitWidth() != SelC->getBitWidth())
393         return ShrinkDemandedConstant(I, OpNo, DemandedMask);
394 
395       // If the constant is already the same as the ICmp, leave it as-is.
396       if (*CmpC == *SelC)
397         return false;
398       // If the constants are not already the same, but can be with the demand
399       // mask, use the constant value from the ICmp.
400       if ((*CmpC & DemandedMask) == (*SelC & DemandedMask)) {
401         I->setOperand(OpNo, ConstantInt::get(I->getType(), *CmpC));
402         return true;
403       }
404       return ShrinkDemandedConstant(I, OpNo, DemandedMask);
405     };
406     if (CanonicalizeSelectConstant(I, 1, DemandedMask) ||
407         CanonicalizeSelectConstant(I, 2, DemandedMask))
408       return I;
409 
410     // Only known if known in both the LHS and RHS.
411     Known = LHSKnown.intersectWith(RHSKnown);
412     break;
413   }
414   case Instruction::Trunc: {
415     // If we do not demand the high bits of a right-shifted and truncated value,
416     // then we may be able to truncate it before the shift.
417     Value *X;
418     const APInt *C;
419     if (match(I->getOperand(0), m_OneUse(m_LShr(m_Value(X), m_APInt(C))))) {
420       // The shift amount must be valid (not poison) in the narrow type, and
421       // it must not be greater than the high bits demanded of the result.
422       if (C->ult(VTy->getScalarSizeInBits()) &&
423           C->ule(DemandedMask.countl_zero())) {
424         // trunc (lshr X, C) --> lshr (trunc X), C
425         IRBuilderBase::InsertPointGuard Guard(Builder);
426         Builder.SetInsertPoint(I);
427         Value *Trunc = Builder.CreateTrunc(X, VTy);
428         return Builder.CreateLShr(Trunc, C->getZExtValue());
429       }
430     }
431   }
432     [[fallthrough]];
433   case Instruction::ZExt: {
434     unsigned SrcBitWidth = I->getOperand(0)->getType()->getScalarSizeInBits();
435 
436     APInt InputDemandedMask = DemandedMask.zextOrTrunc(SrcBitWidth);
437     KnownBits InputKnown(SrcBitWidth);
438     if (SimplifyDemandedBits(I, 0, InputDemandedMask, InputKnown, Depth + 1,
439                              Q)) {
440       // For zext nneg, we may have dropped the instruction which made the
441       // input non-negative.
442       I->dropPoisonGeneratingFlags();
443       return I;
444     }
445     assert(InputKnown.getBitWidth() == SrcBitWidth && "Src width changed?");
446     if (I->getOpcode() == Instruction::ZExt && I->hasNonNeg() &&
447         !InputKnown.isNegative())
448       InputKnown.makeNonNegative();
449     Known = InputKnown.zextOrTrunc(BitWidth);
450 
451     break;
452   }
453   case Instruction::SExt: {
454     // Compute the bits in the result that are not present in the input.
455     unsigned SrcBitWidth = I->getOperand(0)->getType()->getScalarSizeInBits();
456 
457     APInt InputDemandedBits = DemandedMask.trunc(SrcBitWidth);
458 
459     // If any of the sign extended bits are demanded, we know that the sign
460     // bit is demanded.
461     if (DemandedMask.getActiveBits() > SrcBitWidth)
462       InputDemandedBits.setBit(SrcBitWidth-1);
463 
464     KnownBits InputKnown(SrcBitWidth);
465     if (SimplifyDemandedBits(I, 0, InputDemandedBits, InputKnown, Depth + 1, Q))
466       return I;
467 
468     // If the input sign bit is known zero, or if the NewBits are not demanded
469     // convert this into a zero extension.
470     if (InputKnown.isNonNegative() ||
471         DemandedMask.getActiveBits() <= SrcBitWidth) {
472       // Convert to ZExt cast.
473       CastInst *NewCast = new ZExtInst(I->getOperand(0), VTy);
474       NewCast->takeName(I);
475       return InsertNewInstWith(NewCast, I->getIterator());
476     }
477 
478     // If the sign bit of the input is known set or clear, then we know the
479     // top bits of the result.
480     Known = InputKnown.sext(BitWidth);
481     break;
482   }
483   case Instruction::Add: {
484     if ((DemandedMask & 1) == 0) {
485       // If we do not need the low bit, try to convert bool math to logic:
486       // add iN (zext i1 X), (sext i1 Y) --> sext (~X & Y) to iN
487       Value *X, *Y;
488       if (match(I, m_c_Add(m_OneUse(m_ZExt(m_Value(X))),
489                            m_OneUse(m_SExt(m_Value(Y))))) &&
490           X->getType()->isIntOrIntVectorTy(1) && X->getType() == Y->getType()) {
491         // Truth table for inputs and output signbits:
492         //       X:0 | X:1
493         //      ----------
494         // Y:0  |  0 | 0 |
495         // Y:1  | -1 | 0 |
496         //      ----------
497         IRBuilderBase::InsertPointGuard Guard(Builder);
498         Builder.SetInsertPoint(I);
499         Value *AndNot = Builder.CreateAnd(Builder.CreateNot(X), Y);
