 61 /// Evaluate query assuming this condition holds.
 62 struct CondContext {
 63   Value *Cond;
 64   bool Invert = false;
 65   SmallPtrSet<Value *, 4> AffectedValues;
 66 
 67   CondContext(Value *Cond) : Cond(Cond) {}
 68 };
