 868 /// Compute known bits from a shift operator, including those with a
 869 /// non-constant shift amount. Known is the output of this function. Known2 is a
 870 /// pre-allocated temporary with the same bit width as Known and on return
 871 /// contains the known bit of the shift value source. KF is an
 872 /// operator-specific function that, given the known-bits and a shift amount,
 873 /// compute the implied known-bits of the shift operator's result respectively
 874 /// for that shift amount. The results from calling KF are conservatively
 875 /// combined for all permitted shift amounts.
 876 static void computeKnownBitsFromShiftOperator(
 877     const Operator *I, const APInt &DemandedElts, KnownBits &Known,
 878     KnownBits &Known2, unsigned Depth, const SimplifyQuery &Q,
 879     function_ref<KnownBits(const KnownBits &, const KnownBits &, bool)> KF) {
 880   computeKnownBits(I->getOperand(0), DemandedElts, Known2, Depth + 1, Q);
 881   computeKnownBits(I->getOperand(1), DemandedElts, Known, Depth + 1, Q);
 882   // To limit compile-time impact, only query isKnownNonZero() if we know at
 883   // least something about the shift amount.
 884   bool ShAmtNonZero =
 885       Known.isNonZero() ||
 886       (Known.getMaxValue().ult(Known.getBitWidth()) &&
 887        isKnownNonZero(I->getOperand(1), DemandedElts, Q, Depth + 1));
 888   Known = KF(Known2, Known, ShAmtNonZero);
 889 }
